module RefModule(
  input clk,
  input reset,
  output reg [3:0] count
);reg [3:0] next_count;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
      next_count <= 4'b0000;
    end
    else begin
      next_count <= count + 1;
    end
  end

  assign count = next_count;

endmodule
